```javascript
// script.js
const form = document.getElementById('registration-form');
const nameInput = document.getElementById('name');
const emailInput = document.getElementById('email');
const passwordInput = document.getElementById('password');

form.addEventListener('submit', (e) => {
  e.preventDefault();
  const name = nameInput.value.trim();
  const email = emailInput.value.trim();
  const password = passwordInput.value.trim();

  if (name && email && password) {
    const userData = {
      name,
      email,
      password: bcrypt.hashSync(password, 10),
    };

    fetch('/api/register', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(userData),
    })
      .then((response) => response.json())
      .then((data) => {
        console.log(data);
        alert('User registered successfully!');
      })
      .catch((error) => {
        console.error(error);
        alert('Error registering user!');
      });
  } else {
    alert('Please fill in all fields!');
  }
});
```

**Backend (Node.js, Express.js, MongoDB):**

```javascript
// server.js
const express = require('express');
const app = express();
const mongoose = require('mongoose');
const bcrypt = require('bcrypt');
const User = require('./models/User');

mongoose.connect('mongodb://localhost:27017/mydatabase', {
  useNewUrlParser: true,
  useUnifiedTopology: true,
});

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

app.post('/api/register', (req, res) => {
  const { name, email, password } = req.body;

  const hashedPassword = bcrypt.hashSync(password, 10);

  const user = new User({
    name,
    email,
    password: hashedPassword,
  });

  user.save((error, user) => {
    if (error) {
      res.status(500).json({ message: 'Error registering user!' });
    } else {
      res.json({ message: 'User registered successfully!' });
    }
  });
});

app.listen(3000, () => {
  console.log('Server listening on port 3000!');
});
```

```javascript
// models/User.js
const mongoose = require('mongoose');

const userSchema = new mongoose.Schema({
  name: String,
  email: String,
  password: String,
});

const User = mongoose.model('User', userSchema);

module.exports = User;
```

This example script demonstrates a simple user registration form that captures the user's name, email, and password, validates the input data, stores it securely in a MongoDB database using bcrypt, and provides a confirmation message to the user.

**Security Considerations:**

* We use bcrypt to securely hash and store the user's password.
* We validate the input data to prevent SQL injection and cross-site scripting (XSS) attacks.
* We use a secure connection (HTTPS) to protect the user's data in transit.
* We store the user's data in a MongoDB database, which provides a secure and scalable storage solution.

This example script provides a solid foundation for building a secure and scalable web application. However, please note that this is just a starting point, and you should consider additional security measures, such as authentication and authorization, to protect your application.

